                var cert = matches.OfType<X509Certificate2>().FirstOrDefault();
                if (cert == null) throw new FileNotFoundException($"Certificate not found. Thumbprint={normalized} Store={storeName}/{storeLocation}");
                if (requirePrivateKey && !cert.HasPrivateKey) throw new InvalidOperationException($"Certificate does not have a private key. Thumbprint={normalized}");
